import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Lenny's Newsletter — 2026-05-25","description":"","frontmatter":{"title":"Lenny's Newsletter — 2026-05-25","date":"2026-05-25T00:00:00.000Z","source":"Lenny's Newsletter","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-25-lennys-newsletter.md","filePath":"research/ai-news/2026-05/2026-05-25-lennys-newsletter.md","lastUpdated":1779928013000}`),n={name:"research/ai-news/2026-05/2026-05-25-lennys-newsletter.md"};function s(i,e,l,p,h,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="📱-lenny-s-newsletter-—-2026-05-25" tabindex="-1">📱 Lenny&#39;s Newsletter — 2026-05-25 <a class="header-anchor" href="#📱-lenny-s-newsletter-—-2026-05-25" aria-label="Permalink to &quot;📱 Lenny&#39;s Newsletter — 2026-05-25&quot;">​</a></h1><blockquote><p>Lenny Rachitsky 的產品 / 成長策略週報；AI 在 PM 工作流的第一手實踐 來源：<a href="https://www.lennysnewsletter.com/feed" target="_blank" rel="noreferrer">Lenny&#39;s Newsletter</a></p></blockquote><hr><h2 id="the-ai-paradox-more-automation-more-humans-more-work-dan-shipper" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/the-ai-paradox-dan-shipper" target="_blank" rel="noreferrer">The AI paradox: More automation, more humans, more work | Dan Shipper</a> <a class="header-anchor" href="#the-ai-paradox-more-automation-more-humans-more-work-dan-shipper" aria-label="Permalink to &quot;[The AI paradox: More automation, more humans, more work | Dan Shipper](https://www.lennysnewsletter.com/p/the-ai-paradox-dan-shipper)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-24</em></p><p><a href="https://youtu.be/4D3hDmGhFhA" target="_blank" rel="noreferrer"></a></p><p><strong>Dan Shipper</strong> is the co-founder and CEO of Every, a media and software company that&#39;s become a living laboratory for the future of work. Everyone at his company of about 30 people is an AI early adopter; from editors to ops people, they use AI to do much of their work, giving Every a unique lens into where the world is heading. A year ago on this show, Dan predicted that people were sleeping on Claude Code for nontechnical work, which proved to be remarkably prescient. Today he&#39;s back with another set of calls: the SaaS apocalypse is dumb, CLIs are over, the forward deployed engineer is the most valuable new hire, and the only thing you need to do to stay employed is ride the models.</p><p><strong>Listen on<a href="https://youtu.be/4D3hDmGhFhA" target="_blank" rel="noreferrer">YouTube</a>, <a href="https://open.spotify.com/episode/08uyLGouK9iFUpEoIkEyai" target="_blank" rel="noreferrer">Spotify</a>, and <a href="https://podcasts.apple.com/us/podcast/the-ai-paradox-more-automation-more-humans-more-work/id1627920305?i=1000769334366" target="_blank" rel="noreferrer">Apple Podcasts</a></strong></p><h3 id="dan-s-predictions" tabindex="-1">Dan&#39;s predictions: <a class="header-anchor" href="#dan-s-predictions" aria-label="Permalink to &quot;Dan&#39;s predictions:&quot;">​</a></h3><ol><li><p>The future of work will happen inside Codex or Claude Code.</p></li><li><p>Every company will have one &quot;super-agent&quot; inside their Slack that every employee talks to regularly.</p></li><li><p>SaaS is not dead--in fact, Dan is bullish on SaaS stocks. His contrarian take: &quot;I would buy SaaS stocks right now.&quot;</p></li><li><p>SaaS economics will shift: users will bring their own AI tokens into apps, which actually improves SaaS margins.</p></li><li><p>PMs will thrive in the AI era.</p></li><li><p>Full-stack designers will become superheroes.</p></li><li><p>The AI job apocalypse is not happening.</p></li><li><p>Forward deployed engineer is the new most essential role.</p></li><li><p>CLIs are over.</p></li><li><p>Automation is a lie.</p></li><li><p>We will read way more AI-generated writing and we will like it.</p></li><li><p>We&#39;ll be building software for humans and agents to use together.</p></li></ol><hr><h3 id="brought-to-you-by" tabindex="-1">Brought to you by: <a class="header-anchor" href="#brought-to-you-by" aria-label="Permalink to &quot;Brought to you by:&quot;">​</a></h3><p><a href="https://substackcdn.com/image/fetch/$s_!5HV4!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa427b9f9-7c95-4bd6-912f-16040e3676e8_1974x248.png" target="_blank" rel="noreferrer"></a></p><p><strong><a href="https://workos.com/lenny" target="_blank" rel="noreferrer">WorkOS</a></strong> --Make your app enterprise-ready, with SSO, SCIM, RBAC, and more</p><p><strong><a href="https://vanta.com/lenny" target="_blank" rel="noreferrer">Vanta</a></strong> --Automate compliance, manage risk, and accelerate trust with AI</p><h3 id="where-to-find-dan-shipper" tabindex="-1">Where to find Dan Shipper: <a class="header-anchor" href="#where-to-find-dan-shipper" aria-label="Permalink to &quot;Where to find Dan Shipper:&quot;">​</a></h3><p>• X: <a href="https://x.com/danshipper" target="_blank" rel="noreferrer">https://x.com/danshipper</a></p><p>• LinkedIn: <a href="https://www.linkedin.com/in/danshipper/" target="_blank" rel="noreferrer">https://www.linkedin.com/in/danshipper/</a></p><p>• Podcast: <a href="https://every.to/podcast" target="_blank" rel="noreferrer">https://every.to/podcast</a></p><p>• Website: <a href="https://danshipper.com" target="_blank" rel="noreferrer">https://danshipper.com</a></p><h3 id="referenced" tabindex="-1">Referenced: <a class="header-anchor" href="#referenced" aria-label="Permalink to &quot;Referenced:&quot;">​</a></h3><p>• The AI-native startup: 5 products, 7-figure revenue, 100% AI-written code | Dan Shipper (co-founder/CEO of Every): <a href="https://www.lennysnewsletter.com/p/inside-every-dan-shipper" target="_blank" rel="noreferrer">https://www.lennysnewsletter.com/p/inside-every-dan-shipper</a></p><p>• Claude Cowork: <a href="https://claude.com/product/cowork" target="_blank" rel="noreferrer">https://claude.com/product/cowork</a></p><p>• Codex: <a href="https://chatgpt.com/codex" target="_blank" rel="noreferrer">https://chatgpt.com/codex</a></p><p>• Everyone should be using Claude Code more: <a href="https://www.lennysnewsletter.com/p/everyone-should-be-using-claude-code" target="_blank" rel="noreferrer">https://www.lennysnewsletter.com/p/everyone-should-be-using-claude-code</a></p><p>• Every: <a href="https://every.to" target="_blank" rel="noreferrer">https://every.to</a></p><p>• Kieran Klaassen on X: <a href="https://x.com/kieranklaassen" target="_blank" rel="noreferrer">https://x.com/kieranklaassen</a></p><p>• Cora: <a href="https://cora.computer" target="_blank" rel="noreferrer">https://cora.computer</a></p><p>• Kate Lee: <a href="https://every.to/@kate_1767" target="_blank" rel="noreferrer">https://every.to/@kate_1767</a></p><p>• METR (Model Evaluation and Threat Research): <a href="https://metr.org" target="_blank" rel="noreferrer">https://metr.org</a></p><p>• OpenClaw: <a href="https://openclaw.ai" target="_blank" rel="noreferrer">https://openclaw.ai</a></p><p>• Shopify: <a href="https://www.shopify.com" target="_blank" rel="noreferrer">https://www.shopify.com</a></p><p>• Ramp: <a href="https://ramp.com" target="_blank" rel="noreferrer">https://ramp.com</a></p><p>• Brandon Gell on LinkedIn: <a href="http://linkedin.com/in/brandongell" target="_blank" rel="noreferrer">linkedin.com/in/brandongell</a></p><p>• Proof: <a href="https://every.to/on-every/introducing-proof" target="_blank" rel="noreferrer">https://every.to/on-every/introducing-proof</a></p><p>• Devin: <a href="https://devin.ai" target="_blank" rel="noreferrer">https://devin.ai</a></p><p>• Cursor: <a href="https://cursor.com" target="_blank" rel="noreferrer">https://cursor.com</a></p><p>• The rise of Cursor: The $300M ARR AI tool that engineers can&#39;t stop using | Michael Truell (co-founder and CEO): <a href="https://www.lennysnewsletter.com/p/the-rise-of-cursor-michael-truell" target="_blank" rel="noreferrer">https://www.lennysnewsletter.com/p/the-rise-of-cursor-michael-truell</a></p><p>• SpaceX: <a href="https://www.spacex.com" target="_blank" rel="noreferrer">https://www.spacex.com</a></p><p>• GitHub: <a href="https://github.com" target="_blank" rel="noreferrer">https://github.com</a></p><p>• Lenny&#39;s post on X on AI changing job responsibilities: <a href="https://x.com/lennysan/status/2054664138039992600" target="_blank" rel="noreferrer">https://x.com/lennysan/status/2054664138039992600</a></p><p>• General Assembly: <a href="https://generalassemb.ly" target="_blank" rel="noreferrer">https://generalassemb.ly</a></p><p>• Marcus Moretti: <a href="https://every.to/@marcus_fd8302_1" target="_blank" rel="noreferrer">https://every.to/@marcus_fd8302_1</a></p><p>• Spiral: <a href="https://every.to/on-every/introducing-spiral" target="_blank" rel="noreferrer">https://every.to/on-every/introducing-spiral</a></p><p>• Axios: <a href="https://www.axios.com" target="_blank" rel="noreferrer">https://www.axios.com</a></p><p>• Hermes: <a href="https://hermes-agent.nousresearch.com" target="_blank" rel="noreferrer">https://hermes-agent.nousresearch.com</a></p><p>• Viktor: <a href="https://www.viktor.ai" target="_blank" rel="noreferrer">https://www.viktor.ai</a></p><p>• <em>The Dark Wizard</em> on HBO: <a href="https://www.hbomax.com/shows/dark-wizard/76e78c26-21c9-45b4-b84b-4c3e1f8ff763" target="_blank" rel="noreferrer">https://www.hbomax.com/shows/dark-wizard/76e78c26-21c9-45b4-b84b-4c3e1f8ff763</a></p><p>• Alex Honnold: <a href="https://en.wikipedia.org/wiki/Alex_Honnold" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Alex_Honnold</a></p><p>• <em>100 Foot Wave</em> on HBO Max: <a href="https://www.hbomax.com/shows/100-foot-wave/34e489ad-2eca-4078-adb6-6d2b521b407e" target="_blank" rel="noreferrer">https://www.hbomax.com/shows/100-foot-wave/34e489ad-2eca-4078-adb6-6d2b521b407e</a></p><p>• Rob Burbea talks: <a href="https://www.youtube.com/@boubabuddha/playlists" target="_blank" rel="noreferrer">https://www.youtube.com/@boubabuddha/playlists</a></p><p>• David Goggins: <a href="https://en.wikipedia.org/wiki/David_Goggins" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/David_Goggins</a></p><h3 id="recommended-books" tabindex="-1">Recommended books: <a class="header-anchor" href="#recommended-books" aria-label="Permalink to &quot;Recommended books:&quot;">​</a></h3><p>• <em>The Golden Compass</em> : <a href="https://www.amazon.com/Golden-Compass-His-Dark-Materials/dp/0807204714" target="_blank" rel="noreferrer">https://www.amazon.com/Golden-Compass-His-Dark-Materials/dp/0807204714</a></p><p>• <em>The Writing Life</em> : <a href="https://www.amazon.com/Writing-Life-Annie-Dillard/dp/0060919884" target="_blank" rel="noreferrer">https://www.amazon.com/Writing-Life-Annie-Dillard/dp/0060919884</a></p><p>• <em>The Second World War</em> : <a href="https://www.amazon.com/Second-World-War-Volumes/dp/B005NS30ZG" target="_blank" rel="noreferrer">https://www.amazon.com/Second-World-War-Volumes/dp/B005NS30ZG</a></p><p>• <em>The Rigor of Angels: Borges, Heisenberg, Kant, and the Ultimate Nature of Reality</em> : <a href="https://www.amazon.com/Rigor-Angels-Heisenberg-Ultimate-Reality/dp/0593315073" target="_blank" rel="noreferrer">https://www.amazon.com/Rigor-Angels-Heisenberg-Ultimate-Reality/dp/0593315073</a></p><p>• <em>The Power Broker: Robert Moses and the Fall of New York</em> : <a href="https://www.amazon.com/Power-Broker-Robert-Moses-Fall/dp/0394720245" target="_blank" rel="noreferrer">https://www.amazon.com/Power-Broker-Robert-Moses-Fall/dp/0394720245</a></p><hr><p>Production and marketing by <a href="https://penname.co/" target="_blank" rel="noreferrer">https://penname.co/</a>. For inquiries about sponsoring the podcast, email <a href="mailto:podcast@lennyrachitsky.com" target="_blank" rel="noreferrer">podcast@lennyrachitsky.com</a>.</p><p><em>Lenny may be an investor in the companies discussed.</em></p><hr><h2 id="my-biggest-takeaways-from-this-conversation" tabindex="-1">My biggest takeaways from this conversation: <a class="header-anchor" href="#my-biggest-takeaways-from-this-conversation" aria-label="Permalink to &quot;My biggest takeaways from this conversation:&quot;">​</a></h2><p><a href="https://www.lennysnewsletter.com/p/the-ai-paradox-dan-shipper" target="_blank" rel="noreferrer"> Read more </a></p><hr><h2 id="🧠-community-wisdom-best-ai-cold-outreach-app-advice-for-college-students-interested-in-pm-the-state-of-ai-in-design" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach" target="_blank" rel="noreferrer">🧠 Community Wisdom: Best AI cold outreach app, advice for college students interested in PM, the state of AI in design, …</a> <a class="header-anchor" href="#🧠-community-wisdom-best-ai-cold-outreach-app-advice-for-college-students-interested-in-pm-the-state-of-ai-in-design" aria-label="Permalink to &quot;[🧠 Community Wisdom: Best AI cold outreach app, advice for college students interested in PM, the state of AI in design, …](https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-23</em></p><p><em>👋 Hello and welcome to this week&#39;s edition of ✨ <strong>Community Wisdom</strong> ✨ a subscriber-only email, delivered every Saturday, highlighting the most helpful conversations in <a href="https://forms.gle/syq81QDwqbvL3Yn58" target="_blank" rel="noreferrer">our members-only Slack community</a>.</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!KxHU!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa1ca8352-9571-4b81-b041-52374176f4fc_2912x1456.png" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach" target="_blank" rel="noreferrer"> Read more </a></p><hr><h2 id="goodbye-lenny-s-reads" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/goodbye-lennys-reads" target="_blank" rel="noreferrer">Goodbye, Lenny&#39;s Reads!</a> <a class="header-anchor" href="#goodbye-lenny-s-reads" aria-label="Permalink to &quot;[Goodbye, Lenny&#39;s Reads!](https://www.lennysnewsletter.com/p/goodbye-lennys-reads)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-22</em></p><p>After a year of bringing you these audio versions of my newsletter, I&#39;ve decided it&#39;s time to wind down this experiment.</p><p>It&#39;s been a lot of fun making these episodes and it&#39;s been incredible to see how far the technology has developed!</p><p>I&#39;m going to keep all of the Lenny&#39;s Reads episodes up on this channel for another week.</p><p>Thank you so much for listening, it&#39;s been great having you along for the ride.</p><p>If you want to keep up with all my content, make sure to keep up to date here:</p><ul><li><p>Twitter: <a href="https://twitter.com/lennysan" target="_blank" rel="noreferrer">https://twitter.com/lennysan</a></p></li><li><p>LinkedIn: <a href="https://www.linkedin.com/in/lennyrachitsky/" target="_blank" rel="noreferrer">https://www.linkedin.com/in/lennyrachitsky/</a></p></li><li><p>Podcast: <a href="https://www.youtube.com/@LennysPodcast" target="_blank" rel="noreferrer">https://www.youtube.com/@LennysPodcast</a></p></li><li><p>Newsletter: <a href="http://lennysnewsletter.com/" target="_blank" rel="noreferrer">http://lennysnewsletter.com/</a></p></li></ul><p>I&#39;ll see you there.</p><hr><h2 id="what-launched-at-google-i-o-2026-30-minute-day-1-recap" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/what-launched-at-google-io-2026-30" target="_blank" rel="noreferrer">What launched at Google I/O 2026 (30-minute day 1 recap)</a> <a class="header-anchor" href="#what-launched-at-google-i-o-2026-30-minute-day-1-recap" aria-label="Permalink to &quot;[What launched at Google I/O 2026 (30-minute day 1 recap)](https://www.lennysnewsletter.com/p/what-launched-at-google-io-2026-30)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-20</em></p><p>Today is day one of Google I/O 2026, and I walk through every major announcement live--from the new Gemini 3.5 model family to Anti-Gravity 2.0, Google AI Studio, Gemini&#39;s consumer redesign, the Omni video model, Flow, Stitch, and Pomelli. I test them in real time and tell you exactly which ones delivered.</p><p><strong>Listen or watch on<a href="https://youtu.be/S-T12Z-8Tbo" target="_blank" rel="noreferrer">YouTube</a>, <a href="https://open.spotify.com/episode/4VANFEBLOCMxXQC4m5hAbf" target="_blank" rel="noreferrer">Spotify</a>, or <a href="https://podcasts.apple.com/us/podcast/what-launched-at-google-i-o-2026-30-minute-day-1-recap/id1809663079?i=1000768665107" target="_blank" rel="noreferrer">Apple Podcasts</a></strong></p><h3 id="what-you-ll-learn" tabindex="-1">What you&#39;ll learn: <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What you&#39;ll learn:&quot;">​</a></h3><ol><li><p>How Gemini 3.5 Flash benchmarks against Claude and GPT models on speed and agentic coding tasks</p></li><li><p>How Anti-Gravity 2.0&#39;s new features (projects, scheduled tasks, subagents, slash commands) compare to Codex and Claude Code</p></li><li><p>Why the /grill-me slash command could be a more aggressive alternative to Claude Code&#39;s clarification flow--and how to use it</p></li><li><p>How Google AI Studio&#39;s new Workspace integration is designed to own the internal productivity app use case</p></li><li><p>How Google&#39;s new creative tools work in practice: Omni (video generation), Flow (cinematic video editing and character consistency), Stitch (streaming UI design with inline edits), and Pomelli (brand identity and asset generation)</p></li><li><p>Why Google&#39;s launch-to-availability gap is still a problem--and what to do when a featured product doesn&#39;t actually work yet</p></li></ol><hr><h3 id="brought-to-you-by-1" tabindex="-1">Brought to you by: <a class="header-anchor" href="#brought-to-you-by-1" aria-label="Permalink to &quot;Brought to you by:&quot;">​</a></h3><p><a href="https://substackcdn.com/image/fetch/$s_!PzlY!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbc5e8bcb-5cd6-4242-92ea-811fa9b4727e_1600x114.png" target="_blank" rel="noreferrer"></a></p><p><strong><a href="https://magicpatterns.com/howiai" target="_blank" rel="noreferrer">Magic Patterns</a></strong> --Prototypes that look like your product</p><p><strong><a href="https://go.thoughtspot.com/howIAI" target="_blank" rel="noreferrer">Thoughtspot</a></strong> --Build AI-powered analytics into your product</p><h3 id="in-this-episode-we-cover" tabindex="-1">In this episode, we cover: <a class="header-anchor" href="#in-this-episode-we-cover" aria-label="Permalink to &quot;In this episode, we cover:&quot;">​</a></h3><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo" target="_blank" rel="noreferrer">00:00</a>) Google I/O 2026 day 1 overview</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=107s" target="_blank" rel="noreferrer">01:47</a>) Gemini 3.5 flash</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=259s" target="_blank" rel="noreferrer">04:19</a>) Antigravity updates</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=392s" target="_blank" rel="noreferrer">06:32</a>) CLI test and agent features</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=479s" target="_blank" rel="noreferrer">07:59</a>) Core agent features released today--May 19th, 2026</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=583s" target="_blank" rel="noreferrer">09:43</a>) New slash commands</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=680s" target="_blank" rel="noreferrer">11:20</a>) Antigravity test results and takeaways</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=745s" target="_blank" rel="noreferrer">12:25</a>) AI Studio updates</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=832s" target="_blank" rel="noreferrer">13:52</a>) Access issues</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=920s" target="_blank" rel="noreferrer">15:20</a>) Gemini redesign</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1044s" target="_blank" rel="noreferrer">17:24</a>) Gemini image gen test</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1156s" target="_blank" rel="noreferrer">19:16</a>) Omni (video generation)</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1376s" target="_blank" rel="noreferrer">22:56</a>) Flow (cinematic editing)</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1471s" target="_blank" rel="noreferrer">24:31</a>) Avatar creation test</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1605s" target="_blank" rel="noreferrer">26:45</a>) Pomelli and Stitch</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1873s" target="_blank" rel="noreferrer">31:13</a>) Recap and final thoughts</p><h3 id="tools-referenced" tabindex="-1">Tools referenced: <a class="header-anchor" href="#tools-referenced" aria-label="Permalink to &quot;Tools referenced:&quot;">​</a></h3><p>• Gemini 3.5 Flash: <a href="https://deepmind.google/technologies/gemini/" target="_blank" rel="noreferrer">https://deepmind.google/technologies/gemini/</a></p><p>• Antigravity: <a href="https://antigravity.google/" target="_blank" rel="noreferrer">https://antigravity.google/</a></p><p>• Google AI Studio: <a href="https://aistudio.google.com/" target="_blank" rel="noreferrer">https://aistudio.google.com/</a></p><p>• Google Gemini: <a href="https://gemini.google.com/" target="_blank" rel="noreferrer">https://gemini.google.com/</a></p><p>• Omni (video generation): <a href="https://gemini.google/overview/video-generation/" target="_blank" rel="noreferrer">https://gemini.google/overview/video-generation/</a></p><p>• Google Flow: <a href="https://flow.google/" target="_blank" rel="noreferrer">https://flow.google/</a></p><p>• Stitch: <a href="https://stitch.withgoogle.com/" target="_blank" rel="noreferrer">https://stitch.withgoogle.com/</a></p><p>• Pomelli (Google brand tool): <a href="https://labs.google.com/pomelli/about/" target="_blank" rel="noreferrer">https://labs.google.com/pomelli/about/</a></p><h3 id="other-references" tabindex="-1">Other references: <a class="header-anchor" href="#other-references" aria-label="Permalink to &quot;Other references:&quot;">​</a></h3><p>• Google I/O 2026 announcements: <a href="https://blog.google/innovation-and-ai/sundar-pichai-io-2026/" target="_blank" rel="noreferrer">https://blog.google/innovation-and-ai/sundar-pichai-io-2026/</a></p><h3 id="where-to-find-claire-vo" tabindex="-1">Where to find Claire Vo: <a class="header-anchor" href="#where-to-find-claire-vo" aria-label="Permalink to &quot;Where to find Claire Vo:&quot;">​</a></h3><p>ChatPRD: <a href="https://www.chatprd.ai/" target="_blank" rel="noreferrer">https://www.chatprd.ai/</a></p><p>Website: <a href="https://clairevo.com/" target="_blank" rel="noreferrer">https://clairevo.com/</a></p><p>LinkedIn: <a href="https://www.linkedin.com/in/clairevo/" target="_blank" rel="noreferrer">https://www.linkedin.com/in/clairevo/</a></p><p>X: <a href="https://x.com/clairevo" target="_blank" rel="noreferrer">https://x.com/clairevo</a></p><p>Production and marketing by <a href="https://penname.co/" target="_blank" rel="noreferrer">https://penname.co/</a>. For inquiries about sponsoring the podcast, email <a href="mailto:jordan@penname.co" target="_blank" rel="noreferrer">jordan@penname.co</a>.</p><hr><h2 id="the-lenny-and-friends-summit-is-back" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/the-lenny-and-friends-summit-is-back" target="_blank" rel="noreferrer">The Lenny and Friends Summit is back!</a> <a class="header-anchor" href="#the-lenny-and-friends-summit-is-back" aria-label="Permalink to &quot;[The Lenny and Friends Summit is back!](https://www.lennysnewsletter.com/p/the-lenny-and-friends-summit-is-back)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-19</em></p><p><em>👋 Hey there, I&#39;m Lenny. Each week, I answer reader questions about building product, driving growth, and accelerating your career. For more: <a href="https://www.lennysnewsletter.com/podcast" target="_blank" rel="noreferrer">Lenny&#39;s Podcast</a> | <a href="https://www.lennybot.com/" target="_blank" rel="noreferrer">Lennybot</a> | <a href="https://www.youtube.com/@howiaipodcast" target="_blank" rel="noreferrer">How I AI</a> | My favorite <a href="https://maven.com/lenny" target="_blank" rel="noreferrer">AI/PM courses</a>, <a href="https://ultraspeaking.com/lennyslist?via=lenny" target="_blank" rel="noreferrer">public speaking course</a>, and <a href="https://www.benerez.com/copilot/lenny" target="_blank" rel="noreferrer">interview prep copilot</a></em></p><p><a href="https://www.lennysnewsletter.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><p><a href="https://substackcdn.com/image/fetch/$s_!MxcG!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Feff4a635-390d-477c-806b-7e8e0dcabfd3_2700x1000.png" target="_blank" rel="noreferrer"></a></p><p>Two years ago, we held the first-ever Lenny and Friends Summit. It was one of the most meaningful days of my life. Full of in-depth talks, intimate roundtables, and a lot of human connection. At the end of the day, an attendee handed me this note before quickly walking away:</p><p><a href="https://substackcdn.com/image/fetch/$s_!6EhQ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F21e7f7b0-dc61-422a-a66e-f9d1d564b691_4032x2622.jpeg" target="_blank" rel="noreferrer"></a></p><p>There&#39;s such power in IRL events, especially these days and especially for product leaders, who often lack peers they can be real with. Ever since the first summit, I&#39;ve been getting messages about how much y&#39;all want another event like this.</p><p><strong>Today, I &#39;m excited to share that the <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Lenny and Friends Summit</a> returns on Thursday, September 10, in San Francisco! <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a>.</strong></p><p>My vision is to make this the best product event in the world. We&#39;re keeping it intentionally small--every attendee will be handpicked--and along with in-depth talks from the world&#39;s top operators, we&#39;ll have interactive workshops, tons of opportunities to get to know other attendees, and a few fun surprises.</p><p><strong>My three main goals for this summit are to help you:</strong></p><ol><li><p>Deeply understand where the product role is heading</p></li><li><p>Learn tangible skills to thrive in that future</p></li><li><p>Build lasting connections with other world-class leaders</p></li></ol><p>Here&#39;s the initial lineup of speakers, each of whom has a unique lens into the future of building (with more to be announced soon):</p><p><a href="https://substackcdn.com/image/fetch/$s_!_BRP!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F62d4b89a-fbdf-4b9c-a5a6-7b534ec229ea_4800x2700.png" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a></p><p>Given that we&#39;re expecting lots of interest and the venue has limited capacity, we&#39;re asking people to <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">apply to attend</a>. Paid newsletter subscribers will get priority consideration. This summit is for senior product and AI leaders; typical titles include Chief, VP, Director, Senior, Group, Lead, or Principal.</p><p>If you&#39;re just starting your career in product or growth, the content won&#39;t be as relevant for you. I may host a future event geared toward early-career folks.</p><p>To give you a sense of what the last summit felt like, a few messages I got from attendees last year:</p><blockquote><p><strong>&quot; The highest-ROI networking event I have been to.&quot;</strong> --Senior PM</p></blockquote><blockquote><p><strong>&quot; Every aspect of the event was absolutely remarkable.&quot;</strong> --CPO</p></blockquote><blockquote><p><strong>&quot; So many insightful discussions, learnings, and connections, and many tactical takeaways I plan to immediately put in practice.&quot;</strong> --Product Lead</p></blockquote><blockquote><p><strong>&quot; The hit rate of good talks was higher than at any other conference I&#39;ve been to.&quot;</strong> --Sr. Director of Product</p></blockquote><blockquote><p><strong>&quot; A powerful reminder of why I fell in love with building products.&quot;</strong> --Founder</p></blockquote><p>Finally, some of my favorite moments from the day:</p><p><a href="https://substackcdn.com/image/fetch/$s_!Mf0M!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ffa0c9eb4-5f63-43b6-9756-fc6a6f84b2f1_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!WFOM!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F01f7c3b6-797a-4823-8dfd-c70bd5f7665a_5712x4284.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!CsI9!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F52b3fb9e-e074-40f2-b833-f8f347525d62_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!7jSE!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F37a23da1-6f0d-4c0c-860e-d8c9e9d465f9_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!AZ3s!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa9e0f68e-55dc-4d54-82b6-f8ed33a2376c_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!ZVsR!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F91ed8c84-b228-4745-be48-3d2f66d1cb8e_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!ljW_!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ffd2618c1-53db-449c-b319-688a03303300_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p>I&#39;m <em>so</em> excited to be doing this again. Whether you made it to the first summit or missed the chance then, we&#39;ve put a lot of thought into making this one even better: more hands-on workshops, more opportunities to meet other attendees, and more options for how to spend your day.</p><p>See you there!</p><p><a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a></p><p>Any questions? Please email <a href="mailto:info@lennyssummit.com" target="_blank" rel="noreferrer">info@lennyssummit.com</a>, and we&#39;ll do our best to reply promptly.</p><hr><p><strong>If you &#39;re finding this newsletter valuable, share it with a friend, and consider subscribing if you haven&#39;t already. There are <a href="https://www.lennysnewsletter.com/subscribe?group=true" target="_blank" rel="noreferrer">group discounts</a>, <a href="https://www.lennysnewsletter.com/subscribe?gift=true" target="_blank" rel="noreferrer">gift options</a>, and <a href="https://www.lennysnewsletter.com/leaderboard" target="_blank" rel="noreferrer">referral bonuses</a> available.</strong></p><p><a href="https://www.lennysnewsletter.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><p>Sincerely,</p><p>Lenny 👋</p><hr>',169)])])}const f=t(n,[["render",s]]);export{m as __pageData,f as default};
